    85→      case ':':
    86→      case '?':
    87→        needsQuoting = length == 1 || str.charAt(1) == ' ';
    88→      case '0':
    89→      case '1':
    90→      case '2':
    91→      case '3':
    92→      case '4':
    93→      case '5':
    94→      case '6':
    95→      case '7':
    96→      case '8':
    97→      case '9':
    98→      case '+':
    99→      case '.':
   100→      case 'o':
