   176→    var pos = builder.length();
   177→
   178→    if (needsEscaping) {
   179→      emitDoubleQuotedString(str);
   180→    } else if (newlineIndex != -1) {
   181→      emitMultilineString(str, newlineIndex, currIndent);
   182→    } else if (needsQuoting || !hasNonNumberChar && isNumber(str, colonIndex)) {
