   236→          ".NaN",
   237→          ".NAN",
   238→          ".inf",
   239→          ".Inf",
   240→          ".INF",
   241→          "+.inf",
   242→          "+.Inf",
   243→          "+.INF",
   244→          "-.inf",
   245→          "-.Inf",
   246→          "-.INF",
