   276→
   277→    builder.append('|');
   278→    if (str.charAt(0) == ' ') {
   279→      builder.append(indent.length());
   280→    }
   281→
   282→    var length = str.length();
   283→    if (str.charAt(length - 1) == '\n') {
   284→      if (length == 1 || str.charAt(length - 2) == '\n') {
   285→        builder.append('+');
   286→      }
   287→    } else {
   288→      builder.append('-');
   289→    }
   290→
   291→    builder.append('\n');
   292→
   293→    var start = 0;
   294→    for (int i = newlineIndex; i < length; i++) {
   295→      var ch = str.charAt(i);
   296→      if (ch != '\n') continue;
