   298→      if (i == start) {
   299→        // don't add leading indent before newline
   300→        builder.append('\n');
   301→      } else {
   302→        builder.append(currIndent).append(str, start, i + 1);
   303→      }
   304→      start = i + 1;
   305→    }
   306→    if (start < length) {
   307→      builder.append(currIndent).append(str, start, length);
   308→    }
   309→
   310→    currIndent.setLength(currIndent.length() - indent.length());
   311→  }
   312→
   313→  private void emitDoubleQuotedString(String str) {
   314→    builder.append('"');
   315→    escaper.escape(str, builder);
   316→    builder.append('"');
   317→  }
   318→
   319→  private void emitSingleQuotedString(String str, int singleQuoteIndex) {
   320→    builder.append('\'');
   321→
   322→    if (singleQuoteIndex == -1) {
   323→      builder.append(str);
   324→    } else {
   325→      var start = 0;
   326→      var length = str.length();
   327→      for (var i = singleQuoteIndex; i < length; i++) {
   328→        if (str.charAt(i) == '\'') {
   329→          builder.append(str, start, i).append("''");
   330→          start = i + 1;
   331→        }
   332→      }
   333→      if (start < length) {
   334→        builder.append(str, start, length);
   335→      }
   336→    }
   337→
   338→    builder.append('\'');
   339→  }
   340→}
