    var needsEscaping = false;
    var needsQuoting = false;
    var hasNonNumberChar = false;
    var newlineIndex = -1;
    var colonIndex = -1;
    var singleQuoteIndex = -1;

    var first = str.charAt(0);
    switch (first) {
      case '\n':
        newlineIndex = 0;
        break;
      case '\'':
        needsQuoting = true;
        singleQuoteIndex = 0;
        break;
      case '!':
      case '%':
      case '&':
      case '*':
      case '{':
      case '}':
      case '[':
      case ']':
      case ',':
      case '#':
      case '|':
      case '>':
      case '@':
      case '`':
      case '"':
      case ' ':
